{
  "name": "Project Aegis: Deepfake Detection & Incident Intelligence",
  "description": "A production-grade cybersecurity platform for real-time deepfake detection, media forensics, and incident management using Gemini's multi-modal intelligence.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

export enum MediaType {
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO'
}

export enum Severity {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export interface ForensicSignal {
  name: string;
  description: string;
  detected: boolean;
  score: number; // 0-1
}

export interface DetectionIncident {
  id: string;
  timestamp: string;
  mediaType: MediaType;
  fileName: string;
  confidenceScore: number; // 0-100
  isDeepfake: boolean;
  severity: Severity;
  forensics: {
    explanation: string;
    signals: ForensicSignal[];
    metadata?: Record<string, any>;
  };
  filePreview?: string;
}

export interface DashboardStats {
  totalDetections: number;
  deepfakeCount: number;
  audioDetections: number;
  videoDetections: number;
  imageDetections: number;
  avgConfidence: number;
}

import React from 'react';
import { Shield, AlertTriangle, FileSearch, BarChart3, Settings, ShieldAlert, Activity } from 'lucide-react';

export const APP_NAME = "Project Aegis";
export const APP_VERSION = "1.0.2-prod";

export const NAVIGATION_ITEMS = [
  { id: 'dashboard', label: 'Dashboard', icon: <BarChart3 className="w-5 h-5" />, path: '/' },
  { id: 'detect', label: 'Detection Console', icon: <FileSearch className="w-5 h-5" />, path: '/detect' },
  { id: 'incidents', label: 'Incident History', icon: <ShieldAlert className="w-5 h-5" />, path: '/incidents' },
  { id: 'analytics', label: 'Live Analytics', icon: <Activity className="w-5 h-5" />, path: '/analytics' },
  { id: 'settings', label: 'System Config', icon: <Settings className="w-5 h-5" />, path: '/settings' },
];

export const DATASET_REFERENCES = [
  { name: 'FaceForensics++', type: 'Video/Image', description: 'Large-scale dataset for facial manipulation detection.' },
  { name: 'Celeb-DF', type: 'Video', description: 'State-of-the-art DeepFake video dataset.' },
  { name: 'DFDC', type: 'Video', description: 'DeepFake Detection Challenge (Facebook/AWS/Microsoft).' },
  { name: 'ASVspoof 2021', type: 'Audio', description: 'Standard for automatic speaker verification spoofing.' },
];

import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity } from "../types";

const API_KEY = process.env.API_KEY || "";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  /**
   * Performs deepfake analysis on provided media using Gemini 3 Flash.
   * This mimics a production ML pipeline by asking the model to look for specific forensic artifacts.
   */
  async analyzeMedia(
    file: File, 
    mediaType: MediaType, 
    base64Data: string
  ): Promise<Partial<DetectionIncident>> {
    const mimeType = file.type;

    const prompt = `
      Perform a forensic deepfake analysis on this ${mediaType.toLowerCase()} file named "${file.name}".

      Look for the following artifacts:
      1. Image/Video: GAN-generated fingerprints, blurring around face boundaries, unnatural eye reflections, frequency domain anomalies, temporal flickering (if video).
      2. Audio: Spectral inconsistencies, robotic phrasing, lack of natural breathing patterns, phase discontinuities.

      Return a detailed JSON response following this schema:
      {
        "isDeepfake": boolean,
        "confidenceScore": number (0-100),
        "explanation": "Detailed professional forensic explanation",
        "severity": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
        "signals": [
          { "name": "string", "description": "string", "detected": boolean, "score": number (0-1) }
        ]
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isDeepfake: { type: Type.BOOLEAN },
              confidenceScore: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    description: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER }
                  }
                }
              }
            },
            required: ["isDeepfake", "confidenceScore", "explanation", "severity", "signals"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: file.name,
        isDeepfake: result.isDeepfake,
        confidenceScore: result.confidenceScore,
        severity: result.severity as Severity,
        forensics: {
          explanation: result.explanation,
          signals: result.signals
        },
        filePreview: `data:${mimeType};base64,${base64Data}`
      };
    } catch (error) {
      console.error("Gemini Analysis Error:", error);
      throw new Error("Forensic engine failed to process media.");
    }
  }
}

export const geminiService = new GeminiService();

