import React, { useState, useRef } from 'react';
import { Upload, File, ShieldCheck, AlertCircle, Loader2, Play, Info, Eye, Layers } from 'lucide-react';
import { MediaType, DetectionIncident, Severity } from '../types';
import { geminiService } from '../services/geminiService';

interface DetectionConsoleProps {
  onIncidentDetected: (incident: DetectionIncident) => void;
}

const DetectionConsole: React.FC<DetectionConsoleProps> = ({ onIncidentDetected }) => {
  const [file, setFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<DetectionIncident | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHeatmap, setShowHeatmap] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setResult(null);
      setError(null);
      setShowHeatmap(false);
    }
  };

  const readFileAsBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const base64String = (reader.result as string).split(',')[1];
        resolve(base64String);
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });
  };

  const runAnalysis = async () => {
    if (!file) return;
    setIsAnalyzing(true);
    setError(null);

    try {
      const mediaType = file.type.startsWith('image/') ? MediaType.IMAGE : 
                        file.type.startsWith('video/') ? MediaType.VIDEO : MediaType.AUDIO;
      const base64 = await readFileAsBase64(file);
      const detection = await geminiService.analyzeMedia(file, mediaType, base64);

      setResult(detection as DetectionIncident);
      onIncidentDetected(detection as DetectionIncident);
    } catch (err: any) {
      setError(err.message || 'Analysis failed');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="space-y-6">
        <div 
          onClick={() => fileInputRef.current?.click()}
          className={`group relative border-2 border-dashed rounded-3xl p-12 text-center transition-all cursor-pointer overflow-hidden ${
            file ? 'border-blue-500 bg-blue-500/5' : 'border-slate-800 hover:border-slate-600 hover:bg-slate-900'
          }`}
        >
          <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,video/*,audio/*" />

          <div className="relative z-10 flex flex-col items-center">
            <div className={`w-16 h-16 bg-slate-800 rounded-2xl flex items-center justify-center mb-4 transition-transform group-hover:scale-110 duration-300 ${file ? 'bg-blue-600/20' : ''}`}>
              <Upload className={`w-8 h-8 ${file ? 'text-blue-400' : 'text-slate-500'}`} />
            </div>
            {file ? (
              <div className="space-y-1">
                <p className="font-bold text-white text-lg">{file.name}</p>
                <div className="flex items-center justify-center gap-3">
                  <span className="text-xs font-mono px-2 py-0.5 bg-slate-800 rounded text-slate-400 uppercase">{file.type.split('/')[1]}</span>
                  <span className="text-xs text-slate-500">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
                </div>
              </div>
            ) : (
              <div>
                <p className="font-semibold text-white text-lg">Ingest Investigative Media</p>
                <p className="text-sm text-slate-500 mt-2">Drop files or click to browse secure local storage</p>
              </div>
            )}
          </div>
        </div>

        {file && !isAnalyzing && !result && (
          <button 
            onClick={runAnalysis}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-5 rounded-2xl shadow-2xl shadow-blue-900/30 transition-all flex items-center justify-center gap-3 group"
          >
            <ShieldCheck className="w-6 h-6 group-hover:scale-110 transition-transform" />
            Execute Forensic Pipeline
          </button>
        )}

        {isAnalyzing && (
          <div className="w-full bg-slate-900 border border-slate-800 p-10 rounded-3xl text-center space-y-6 relative overflow-hidden">
            <div className="absolute inset-0 bg-blue-500/5 animate-pulse"></div>
