                 <p className={`text-sm font-bold ${result.isDeepfake ? 'text-red-400' : 'text-emerald-400'}`}>
                    {result.isDeepfake ? 'FAILED_CHECKS' : 'PASSED_CHECKS'}
                 </p>
              </div>
              <div className="p-4 bg-slate-900 border border-slate-800 rounded-2xl">
                 <p className="text-[10px] text-slate-500 font-bold uppercase mb-1">Inference Latency</p>
                 <p className="text-sm font-bold text-slate-200">1.24s (LOCAL_AVG)</p>
