import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // Initializing with process.env.API_KEY directly as required by guidelines
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Performs deepfake analysis on provided media using Gemini 3 Flash.
   * This mimics a production ML pipeline by asking the model to look for specific forensic artifacts.
   */
  async analyzeMedia(
    file: File, 
    mediaType: MediaType, 
    base64Data: string
  ): Promise<Partial<DetectionIncident>> {
    const mimeType = file.type;

    const prompt = `
      Perform a forensic deepfake analysis on this ${mediaType.toLowerCase()} file named "${file.name}".

      Look for the following artifacts:
      1. Image/Video: GAN-generated fingerprints, blurring around face boundaries, unnatural eye reflections, frequency domain anomalies, temporal flickering (if video).
      2. Audio: Spectral inconsistencies, robotic phrasing, lack of natural breathing patterns, phase discontinuities.

      Return a detailed JSON response following this schema:
      {
        "isDeepfake": boolean,
        "confidenceScore": number (0-100),
        "explanation": "Detailed professional forensic explanation",
        "severity": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
        "signals": [
          { "name": "string", "description": "string", "detected": boolean, "score": number (0-1) }
        ]
      }
    `;

    try {
      // Calling generateContent with both model name and prompt/parts
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: prompt }
          ]
        },
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              isDeepfake: { type: Type.BOOLEAN },
              confidenceScore: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    description: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER }
                  }
                }
              }
            },
            required: ["isDeepfake", "confidenceScore", "explanation", "severity", "signals"]
          }
        }
      });

      // Directly accessing the .text property of GenerateContentResponse
      const result = JSON.parse(response.text || "{}");

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: file.name,
        isDeepfake: result.isDeepfake,
        confidenceScore: result.confidenceScore,
        severity: result.severity as Severity,
        forensics: {
          explanation: result.explanation,
          signals: result.signals
        },
        filePreview: `data:${mimeType};base64,${base64Data}`
      };
    } catch (error) {
      console.error("Gemini Analysis Error:", error);
      throw new Error("Forensic engine failed to process media.");
    }
  }
}

