import React, { useState, useRef } from 'react';
import { Upload, ShieldCheck, AlertCircle, Loader2, Play, Info, Eye, Layers, Activity, FileText } from 'lucide-react';
import { MediaType, DetectionIncident, Severity } from '../types';
import { geminiService } from '../services/geminiService';

interface DetectionConsoleProps {
  onIncidentDetected: (incident: DetectionIncident) => void;
}

const DetectionConsole: React.FC<DetectionConsoleProps> = ({ onIncidentDetected }) => {
  const [file, setFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<DetectionIncident | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showHeatmap, setShowHeatmap] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setResult(null);
      setError(null);
      setShowHeatmap(false);
    }
  };

  const runAnalysis = async () => {
    if (!file) return;
    setIsAnalyzing(true);
    setError(null);

    try {
      const reader = new FileReader();
      const base64Promise = new Promise<string>((resolve) => {
        reader.onload = () => resolve((reader.result as string).split(',')[1]);
        reader.readAsDataURL(file);
      });

      const mediaType = file.type.startsWith('image/') ? MediaType.IMAGE : 
                        file.type.startsWith('video/') ? MediaType.VIDEO : MediaType.AUDIO;

      const base64 = await base64Promise;
      const detection = await geminiService.analyzeMedia(file, mediaType, base64);

      setResult(detection);
      onIncidentDetected(detection);
    } catch (err: any) {
      setError(err.message || 'Forensic analysis failed.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="space-y-6">
        <div 
          onClick={() => !isAnalyzing && fileInputRef.current?.click()}
          className={`group relative border-2 border-dashed rounded-3xl p-12 text-center transition-all cursor-pointer overflow-hidden ${
            isAnalyzing ? 'opacity-50 cursor-not-allowed' : ''
          } ${
            file ? 'border-blue-500 bg-blue-500/5' : 'border-slate-800 hover:border-slate-600 hover:bg-slate-900'
          }`}
        >
          <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,video/*,audio/*" disabled={isAnalyzing} />
          <div className="relative z-10 flex flex-col items-center">
            <div className={`w-16 h-16 bg-slate-800 rounded-2xl flex items-center justify-center mb-4 transition-transform group-hover:scale-110 duration-300 ${file ? 'bg-blue-600/20 text-blue-400' : 'text-slate-500'}`}>
              <Upload className="w-8 h-8" />
            </div>
            {file ? (
              <div className="space-y-1">
                <p className="font-bold text-white text-lg">{file.name}</p>
                <p className="text-xs text-slate-500">{(file.size / 1024 / 1024).toFixed(2)} MB • READY</p>
              </div>
            ) : (
              <div>
                <p className="font-semibold text-white text-lg">Ingest Media</p>
                <p className="text-sm text-slate-500 mt-2">Support: Image, Video, Audio</p>
              </div>
            )}
          </div>
        </div>

        {file && !isAnalyzing && !result && (
          <button 
            onClick={runAnalysis}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-5 rounded-2xl shadow-xl shadow-blue-900/30 transition-all flex items-center justify-center gap-3"
          >
            <ShieldCheck className="w-6 h-6" />
            Start Analysis
          </button>
        )}

        {isAnalyzing && (
          <div className="w-full bg-slate-900 border border-slate-800 p-10 rounded-3xl text-center space-y-6">
            <Loader2 className="w-12 h-12 text-blue-500 animate-spin mx-auto" />
            <div className="space-y-2">
              <p className="text-xl font-bold text-white">Analyzing Forensic Artifacts...</p>
              <p className="text-xs text-blue-400 font-mono animate-pulse uppercase">CNN_INFERENCE_IN_PROGRESS</p>
            </div>
            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
              <div className="h-full bg-blue-500 animate-[loading_2s_ease-in-out_infinite] w-1/3"></div>
            </div>
          </div>
        )}

        {error && (
          <div className="bg-red-500/10 border border-red-500/50 p-4 rounded-xl flex gap-3 text-red-400 animate-in fade-in zoom-in">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p className="text-sm font-medium">{error}</p>
          </div>
        )}

        {result && (
           <div className="grid grid-cols-2 gap-4 animate-in slide-in-from-left-4">
              <div className="p-4 bg-slate-900 border border-slate-800 rounded-2xl">
                 <p className="text-[10px] text-slate-500 font-bold uppercase mb-1">Measured Latency</p>
                 <p className="text-sm font-mono font-bold text-blue-400">{result.processingTimeMs}ms</p>
              </div>
              <div className="p-4 bg-slate-900 border border-slate-800 rounded-2xl">
                 <p className="text-[10px] text-slate-500 font-bold uppercase mb-1">Detection Result</p>
                 <p className={`text-sm font-bold uppercase ${result.isDeepfake ? 'text-red-400' : 'text-emerald-400'}`}>
                    {result.label}
                 </p>
              </div>
           </div>
        )}
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden flex flex-col min-h-[600px] shadow-inner relative">
        {result ? (
          <div className="flex-1 flex flex-col animate-in fade-in zoom-in-95 duration-500">
