  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard incidents={incidents} />;
      case 'detect':
        return <DetectionConsole onIncidentDetected={handleNewIncident} />;
      case 'incidents':
        return <IncidentTable incidents={incidents} />;
      case 'analytics':
        return <AnalyticsView incidents={incidents} />;
      case 'settings':
        return (
          <div className="space-y-6 max-w-4xl mx-auto animate-in fade-in duration-500">
            <div className="bg-slate-900 border border-slate-800 rounded-3xl p-10 shadow-2xl">
              <h3 className="text-2xl font-bold mb-8 text-white tracking-tight">System Node Configuration</h3>
              <div className="space-y-8">
                <div className="flex items-center justify-between p-6 bg-slate-800/30 rounded-2xl border border-slate-700">
                  <div className="max-w-md">
                    <h4 className="font-bold text-slate-100 uppercase tracking-widest text-[10px] mb-2">Escalation Threshold</h4>
                    <p className="text-xs text-slate-500 leading-relaxed">Incidents exceeding this probability will trigger high-priority alerts.</p>
                  </div>
                  <div className="flex items-center gap-6">
                     <span className="text-xs font-mono font-bold text-blue-400">85%</span>
                     <input type="range" className="accent-blue-500 w-32" defaultValue={85} />
                  </div>
                </div>
                <div className="flex items-center justify-between p-6 bg-slate-800/30 rounded-2xl border border-slate-700">
                  <div className="max-w-md">
                    <h4 className="font-bold text-slate-100 uppercase tracking-widest text-[10px] mb-2">Inference Engine</h4>
                    <p className="text-xs text-slate-500 leading-relaxed">Selecting the Gemini 3 Flash core for optimal latency vs accuracy.</p>
                  </div>
                  <select className="bg-slate-900 border-none rounded-xl text-xs font-bold px-4 py-2 text-slate-200 outline-none ring-1 ring-slate-700">
                    <option selected>GEMINI_3_FLASH_PROD</option>
                    <option>GEMINI_2.5_FLASH_LITE</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="bg-red-500/5 border border-red-500/20 rounded-3xl p-10 flex flex-col items-start shadow-inner">
              <div className="flex items-center gap-4 text-red-500 mb-6">
                <AlertCircle className="w-6 h-6" />
                <h4 className="font-bold uppercase tracking-widest text-sm">Destructive Actions</h4>
              </div>
              <p className="text-xs text-slate-500 mb-8 max-w-lg leading-relaxed">Purging the forensic audit trail is irreversible. All incident metadata and historical telemetry will be erased.</p>
              <button 
                onClick={() => {
                  if(confirm('Wipe forensic history? This will clear all data-driven metrics.')) {
                    setIncidents([]);
                    localStorage.removeItem(STORAGE_KEY);
                  }
                }}
                className="bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white border border-red-500/30 px-10 py-4 rounded-2xl text-[10px] font-black transition-all uppercase tracking-widest shadow-xl shadow-red-900/10"
              >
                Flush System Cache
              </button>
            </div>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

