import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity, MediaPart } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  /**
   * Performs deepfake analysis on provided media parts (frames or raw file).
   */
  async analyzeMedia(
    fileName: string, 
    mediaType: MediaType, 
    parts: MediaPart[]
  ): Promise<DetectionIncident> {
    const startTime = performance.now();

    const systemInstruction = `
      You are an AI Forensic Analyst specializing in synthetic media detection.
      You are provided with ${parts.length} parts representing a ${mediaType} file.
      Analyze the input for:
      1. GAN artifacts (checkerboard patterns, unusual noise).
      2. Temporal inconsistencies (flickering, landmark misalignment).
      3. Spectral anomalies (synthetic voice signatures).

      Return a JSON object with:
      - label: "deepfake" or "genuine"
      - confidence: float 0.0-1.0
      - explanation: brief technical reasoning
      - severity: "LOW", "MEDIUM", "HIGH", or "CRITICAL"
      - signals: Array of {name, detected, score}
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            parts: [
              { text: systemInstruction },
              ...parts.map(p => ({
                inlineData: { data: p.data, mimeType: p.mimeType }
              }))
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              label: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER }
                  }
                }
              }
            },
            required: ["label", "confidence", "explanation", "severity", "signals"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const endTime = performance.now();

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: fileName,
        label: result.label as 'deepfake' | 'genuine',
        isDeepfake: result.label === 'deepfake',
        confidenceScore: Math.round(result.confidence * 100),
        severity: result.severity as Severity,
        processingTimeMs: Math.round(endTime - startTime),
        forensics: {
          explanation: result.explanation,
          signals: result.signals
        },
        filePreview: parts[0]?.mimeType.startsWith('image/') ? `data:${parts[0].mimeType};base64,${parts[0].data}` : undefined
      };
    } catch (error) {
      console.error("Forensic Engine Error:", error);
      throw new Error("The Forensic Engine failed to process. Memory overflow prevented or API limit reached.");
    }
  }
}

