export enum MediaType {
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO'
}

export enum Severity {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export type ClassificationType = 'genuine' | 'deepfake' | 'ai_generated';

export interface ForensicSignal {
  name: string;
  description: string;
  detected: boolean;
  score: number; // 0-1
  engine: 'deepfake' | 'synthetic'; // New field to track engine source
}

export interface MediaPart {
  data: string; // Base64
  mimeType: string;
}

export interface DetectionIncident {
  id: string;
  timestamp: string;
  mediaType: MediaType;
  fileName: string;
  confidenceScore: number; // 0-100
  classification: ClassificationType;
  isDeepfake: boolean; // Retained for backward compatibility in some views
  severity: Severity;
  processingTimeMs: number;
  forensics: {
    explanation: string;
    signals: ForensicSignal[];
    metadata?: {
      synthetic_probability: number;
      impersonation_probability: number;
      engine_source: string;
    };
  };
  filePreview?: string;
}

export interface DashboardStats {
  totalDetections: number;
  deepfakeCount: number;
  aiGeneratedCount: number;
  genuineCount: number;
  avgConfidence: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity, MediaPart, ClassificationType } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async analyzeMedia(
    fileName: string, 
    mediaType: MediaType, 
    parts: MediaPart[]
  ): Promise<DetectionIncident> {
    const startTime = performance.now();

    const systemInstruction = `
      You are a dual-engine AI Forensic Analyst. Your task is to classify media into three distinct categories:
      1. GENUINE: Natural, unmanipulated media.
      2. DEEPFAKE: Identity manipulation (swapping faces, voices, or impersonating a specific real person).
      3. AI-GENERATED: Synthetic media created by generative models (Stable Diffusion, Midjourney, DALL-E, Sora, ElevenLabs) that may not involve a specific real identity.

      ANALYSIS LOGIC:
      - Engine A (Deepfake): Look for identity misalignment, boundary artifacts, and landmark inconsistencies.
      - Engine B (Synthetic): Look for GAN/Diffusion noise, frequency domain artifacts (FFT/DCT), over-regular patterns, and spectral smoothness.

      PRIORITY RULES:
      - High Engine A confidence -> DEEPFAKE.
      - Low Engine A + High Engine B confidence -> AI-GENERATED.
      - Low both -> GENUINE.

      Return a JSON object:
      {
        "classification": "genuine" | "deepfake" | "ai_generated",
        "confidence": float 0.0-1.0,
        "explanation": "Technical reasoning for the final classification",
        "severity": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
        "synthetic_probability": float 0.0-1.0,
        "impersonation_probability": float 0.0-1.0,
        "signals": Array of { "name": string, "detected": boolean, "score": float, "engine": "deepfake" | "synthetic" }
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            parts: [
              { text: systemInstruction },
              ...parts.map(p => ({
                inlineData: { data: p.data, mimeType: p.mimeType }
              }))
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              classification: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              synthetic_probability: { type: Type.NUMBER },
              impersonation_probability: { type: Type.NUMBER },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER },
                    engine: { type: Type.STRING }
                  }
                }
              }
            },
            required: ["classification", "confidence", "explanation", "severity", "signals", "synthetic_probability", "impersonation_probability"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const endTime = performance.now();

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: fileName,
        classification: result.classification as ClassificationType,
        isDeepfake: result.classification === 'deepfake',
        confidenceScore: Math.round(result.confidence * 100),
        severity: result.severity as Severity,
        processingTimeMs: Math.round(endTime - startTime),
        forensics: {
          explanation: result.explanation,
          signals: result.signals,
          metadata: {
            synthetic_probability: result.synthetic_probability,
            impersonation_probability: result.impersonation_probability,
            engine_source: result.classification === 'deepfake' ? 'Deepfake Engine' : 'Synthetic Media Engine'
          }
        },
        filePreview: parts[0]?.mimeType.startsWith('image/') ? `data:${parts[0].mimeType};base64,${parts[0].data}` : undefined
      };
    } catch (error) {
      console.error("Forensic Engine Error:", error);
      throw new Error("Dual-Engine Forensic analysis failed. Please retry with a smaller file.");
    }
  }
}

