}

import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity, MediaPart, ClassificationType } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async analyzeMedia(
    fileName: string, 
    mediaType: MediaType, 
    parts: MediaPart[]
  ): Promise<DetectionIncident> {
    const startTime = performance.now();

    const systemInstruction = `
      You are a Senior Media Forensics Authenticity Engine. Your goal is to verify if media originates from a physical sensor/microphone or a generative model.

      TRIPLE-ENGINE ARCHITECTURE:
      1. DEEPFAKE ENGINE: Detects identity manipulation (Face-swaps, voice clones).
      2. SYNTHETIC ARTIFACT ENGINE: Detects GAN/Diffusion noise, checkerboard artifacts, latent space smoothing.
      3. PROVENANCE ENGINE (CRITICAL): Detects evidence of physical capture.
         - Search for: Photon shot noise, rolling shutter skew, lens chromatic aberration, sensor-specific noise fingerprints, inertial motion jitter.
         - Absence of these signals in high-quality media is a red flag for synthetic origin.

      STRICT CLASSIFICATION LOGIC:
      - GENUINE: ONLY allowed if physical capture signals are present AND no manipulation is found.
      - DEEPFAKE: Identity manipulation detected (high Engine 1 score).
      - AI-GENERATED: High Engine 2 score OR (Low Engine 1 score AND LOW Provenance/Physics score).

      High-quality stock AI video (e.g. Sora, Runway) often looks "perfect" but lacks sensor noise. These MUST be classified as AI-GENERATED.

      Return a JSON object:
      {
        "classification": "genuine" | "deepfake" | "ai_generated",
        "confidence": float 0.0-1.0,
        "physical_capture_likelihood": float 0.0-1.0,
        "synthetic_generation_likelihood": float 0.0-1.0,
        "explanation": "Technical reasoning focusing on provenance physics and sensor artifacts",
        "severity": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
        "signals": Array of { "name": string, "detected": boolean, "score": float, "engine": "deepfake" | "synthetic" | "provenance" }
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            parts: [
              { text: systemInstruction },
              ...parts.map(p => ({
                inlineData: { data: p.data, mimeType: p.mimeType }
              }))
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              classification: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
              physical_capture_likelihood: { type: Type.NUMBER },
              synthetic_generation_likelihood: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER },
                    engine: { type: Type.STRING }
                  }
                }
              }
            },
            required: ["classification", "confidence", "explanation", "severity", "signals", "physical_capture_likelihood", "synthetic_generation_likelihood"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const endTime = performance.now();

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: fileName,
        classification: result.classification as ClassificationType,
        isDeepfake: result.classification === 'deepfake',
        confidenceScore: Math.round(result.confidence * 100),
        severity: result.severity as Severity,
        processingTimeMs: Math.round(endTime - startTime),
        provenance: {
          physical_capture_likelihood: result.physical_capture_likelihood,
          synthetic_generation_likelihood: result.synthetic_generation_likelihood
        },
        forensics: {
          explanation: result.explanation,
          signals: result.signals,
          metadata: {
            synthetic_probability: result.synthetic_generation_likelihood,
            impersonation_probability: result.classification === 'deepfake' ? result.confidence : 0,
            engine_source: 'Triple-Engine Fusion'
          }
        },
        filePreview: parts[0]?.mimeType.startsWith('image/') ? `data:${parts[0].mimeType};base64,${parts[0].data}` : undefined
      };
    } catch (error) {
      console.error("Provenance Engine Error:", error);
      throw new Error("Provenance & Authenticity verification failed. Possible high-complexity synthetic input causing latent timeout.");
    }
  }
}

