export enum MediaType {
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO'
}

export enum Severity {
  LOW = 'LOW',
  MEDIUM = 'MEDIUM',
  HIGH = 'HIGH',
  CRITICAL = 'CRITICAL'
}

export type ClassificationType = 'genuine' | 'deepfake' | 'ai_generated';

export interface ForensicSignal {
  name: string;
  description: string;
  detected: boolean;
  score: number; // 0-1
  engine: 'deepfake' | 'synthetic' | 'provenance' | 'consistency'; // Added consistency engine
}

export interface MediaPart {
  data: string; // Base64
  mimeType: string;
}

export interface DetectionIncident {
  id: string;
  timestamp: string;
  mediaType: MediaType;
  fileName: string;
  confidenceScore: number; // 0-100
  classification: ClassificationType;
  isDeepfake: boolean; 
  severity: Severity;
  processingTimeMs: number;
  provenance: {
    physical_capture_likelihood: number; // 0-1
    synthetic_generation_likelihood: number; // 0-1
    capture_chain_consistency: number; // 0-1 New CCCE metric
  };
  forensics: {
    explanation: string;
    signals: ForensicSignal[];
    metadata?: {
      synthetic_probability: number;
      impersonation_probability: number;
      engine_source: string;
      consistency_failures?: string[];
    };
  };
  filePreview?: string;
}

export interface DashboardStats {
  totalDetections: number;
  deepfakeCount: number;
