  genuineCount: number;
  avgConfidence: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity, MediaPart, ClassificationType } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async analyzeMedia(
    fileName: string, 
    mediaType: MediaType, 
    parts: MediaPart[]
  ): Promise<DetectionIncident> {
    const startTime = performance.now();

    const systemInstruction = `
      You are the Capture-Chain Consistency Engine (CCCE) for Project Aegis.
      Your primary objective is to determine if media could have been captured by a physical camera from photon to file, or if it is a synthetic reconstruction.

      FAILURE CLASS PREVENTION:
      Premium AI media (Sora, Runway, Midjourney) often injects realistic sensor noise and lens artifacts. You must verify if these signals obey PHYSICAL CAUSALITY.

      CCCE MANDATORY AUDIT:
      1. Cross-Signal Dependency: Does sensor noise increase/decrease correctly with exposure and focal depth? Do lens aberrations drift correctly with frame motion?
      2. Temporal Noise Evolution: Real sensors show stochastic noise drift and temperature-linked variance. Stationary or frame-independent noise is evidence of synthetic origin.
      3. Codec-Sensor Alignment: Does the codec quantization behavior match the sensor noise distribution? Is noise "pasted" over compressed blocks?
      4. Metadata-Physics Coherence: Does the absence of consistent firmware/capture metadata contradict the "realistic" physics presented?

      STRICT CLASSIFICATION LOGIC:
      - GENUINE: ONLY if (Physical Capture Likelihood > 0.8) AND (Capture-Chain Consistency > 0.85).
      - AI-GENERATED: If consistency is low, REGARDLESS of visual realism. Premium AI stock video with injected physics MUST be classified as AI-GENERATED if the signals lack causal linkage.
      - DEEPFAKE: Identity manipulation detected.

      Return a JSON object:
      {
        "classification": "genuine" | "deepfake" | "ai_generated",
        "confidence": float 0.0-1.0,
        "physical_capture_likelihood": float 0.0-1.0,
        "synthetic_generation_likelihood": float 0.0-1.0,
        "capture_chain_consistency": float 0.0-1.0,
        "explanation": "State: 'Physical artifacts are present but lack end-to-end capture-chain consistency' if applicable.",
        "severity": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
        "consistency_failures": string[],
        "signals": Array of { "name": string, "detected": boolean, "score": float, "engine": "deepfake" | "synthetic" | "provenance" | "consistency" }
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            parts: [
              { text: systemInstruction },
              ...parts.map(p => ({
                inlineData: { data: p.data, mimeType: p.mimeType }
              }))
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              classification: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
              physical_capture_likelihood: { type: Type.NUMBER },
              synthetic_generation_likelihood: { type: Type.NUMBER },
              capture_chain_consistency: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              consistency_failures: { type: Type.ARRAY, items: { type: Type.STRING } },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER },
                    engine: { type: Type.STRING }
                  }
                }
              }
            },
            required: ["classification", "confidence", "explanation", "severity", "signals", "physical_capture_likelihood", "synthetic_generation_likelihood", "capture_chain_consistency"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const endTime = performance.now();

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: fileName,
        classification: result.classification as ClassificationType,
        isDeepfake: result.classification === 'deepfake',
        confidenceScore: Math.round(result.confidence * 100),
        severity: result.severity as Severity,
        processingTimeMs: Math.round(endTime - startTime),
        provenance: {
          physical_capture_likelihood: result.physical_capture_likelihood,
          synthetic_generation_likelihood: result.synthetic_generation_likelihood,
          capture_chain_consistency: result.capture_chain_consistency
        },
        forensics: {
          explanation: result.explanation,
          signals: result.signals,
          metadata: {
            synthetic_probability: result.synthetic_generation_likelihood,
            impersonation_probability: result.classification === 'deepfake' ? result.confidence : 0,
            engine_source: 'CCCE-Verification',
            consistency_failures: result.consistency_failures
          }
        },
        filePreview: parts[0]?.mimeType.startsWith('image/') ? `data:${parts[0].mimeType};base64,${parts[0].data}` : undefined
      };
    } catch (error) {
      console.error("CCCE Engine Error:", error);
      throw new Error("Capture-Chain Consistency audit failed. Input complexity suggests high-entropy synthetic media.");
    }
  }
}

