              <div className={`p-5 bg-slate-900 border border-slate-800 rounded-2xl flex justify-between items-center ${result.classification === 'genuine' ? 'border-emerald-500/30 bg-emerald-500/5' : result.classification === 'hybrid' ? 'border-purple-500/30 bg-purple-500/5' : ''}`}>
                 <div>
