                      "Project Aegis looks for evidence of natural, unscripted reality. If a video feels like a 'perfect concept' or follows common AI patterns, we mark it as AI-Assisted, even if the image quality is indistinguishable from a camera."
                    </p>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center p-12 text-center opacity-60">
            <div className="w-24 h-24 bg-slate-800/50 rounded-full flex items-center justify-center mb-8 border border-slate-700/50">
              <Activity className="w-10 h-10 text-slate-600" />
            </div>
            <h3 className="text-xl font-black text-white mb-3 uppercase tracking-tighter italic">Verification Terminal</h3>
            <p className="text-xs text-slate-500 max-w-xs font-bold uppercase tracking-widest leading-loose">Awaiting media input. Upload a file to start the verification process and check for AI manipulation signatures.</p>
          </div>
        )}
      </div>
      <style>{`
        @keyframes scan-line {
          0% { top: -100%; }
          100% { top: 100%; }
        }
        .animate-scan-line {
          position: absolute;
          width: 100%;
          height: 3px;
          background: rgba(59, 130, 246, 0.5);
          box-shadow: 0 0 20px rgba(59, 130, 246, 0.8);
          animation: scan-line 4s linear infinite;
        }
      `}</style>
    </div>
  );
};

