import { GoogleGenAI, Type } from "@google/genai";
import { MediaType, DetectionIncident, Severity, MediaPart, ClassificationType } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async analyzeMedia(
    fileName: string, 
    mediaType: MediaType, 
    parts: MediaPart[]
  ): Promise<DetectionIncident> {
    const startTime = performance.now();

    const systemInstruction = `
      You are a forensic media analyst for Project Aegis. 
      Your objective is to evaluate whether the provided media shows signs of artificial manipulation or computer generation.

      VERIFICATION GUIDELINES:
      - A "GENUINE" result should be reserved for media that appears to be a direct recording of a physical event, containing the natural imperfections and random details typical of real-world captures.
      - Look for "Synthetic Signatures": This includes scenes that look too perfect, follow common AI style patterns, or lack the expected noise and irregularities of a camera sensor.
      - Evaluate "Visual and Audio Logic": Do the lighting, shadows, and sound waves align with physical reality?

      CLASSIFICATION HIERARCHY:
      1. DEEPFAKE: Use this if the identity of a person has been digitally altered or swapped.
      2. AI-GENERATED: Use this if the entire image or video appears to have been created by a computer from scratch.
      3. AI-ASSISTED / HYBRID MEDIA: Use this if the media looks like a real recording but has been modified by AI, or if the scene feels "staged" by an AI model despite having realistic textures.
      4. GENUINE: Use this only if the media passes all checks for natural authenticity.

      HYBRID MEDIA GUIDANCE:
      If the technical signals (like grain or lighting) seem real, but the overall content feels like an AI-generated concept (e.g., a "perfect" digital office or an idealized person), classify as "hybrid".

      Return JSON:
      {
        "classification": "genuine" | "deepfake" | "ai_generated" | "hybrid",
        "confidence": float 0.0-1.0,
        "physical_capture_likelihood": float 0.0-1.0,
        "synthetic_generation_likelihood": float 0.0-1.0,
        "capture_chain_consistency": float 0.0-1.0,
        "semantic_authenticity": float 0.0-1.0,
        "explanation": "Provide a clear, human-readable explanation of your findings.",
        "severity": "LOW" | "MEDIUM" | "HIGH" | "CRITICAL",
        "semantic_priors": string[],
        "signals": Array of { "name": string, "detected": boolean, "score": float, "engine": "deepfake" | "synthetic" | "provenance" | "consistency" | "semantic" }
      }
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            parts: [
              { text: systemInstruction },
              ...parts.map(p => ({
                inlineData: { data: p.data, mimeType: p.mimeType }
              }))
            ]
          }
        ],
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              classification: { type: Type.STRING },
              confidence: { type: Type.NUMBER },
              physical_capture_likelihood: { type: Type.NUMBER },
              synthetic_generation_likelihood: { type: Type.NUMBER },
              capture_chain_consistency: { type: Type.NUMBER },
              semantic_authenticity: { type: Type.NUMBER },
              explanation: { type: Type.STRING },
              severity: { type: Type.STRING },
              semantic_priors: { type: Type.ARRAY, items: { type: Type.STRING } },
              signals: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    detected: { type: Type.BOOLEAN },
                    score: { type: Type.NUMBER },
                    engine: { type: Type.STRING }
                  }
                }
              }
            },
            required: ["classification", "confidence", "explanation", "severity", "signals", "physical_capture_likelihood", "synthetic_generation_likelihood", "capture_chain_consistency", "semantic_authenticity"]
          }
        }
      });

      const result = JSON.parse(response.text || "{}");
      const endTime = performance.now();

      return {
        id: `AEGIS-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        timestamp: new Date().toISOString(),
        mediaType,
        fileName: fileName,
        classification: result.classification as ClassificationType,
        isDeepfake: result.classification === 'deepfake',
        confidenceScore: Math.round(result.confidence * 100),
        severity: result.severity as Severity,
        processingTimeMs: Math.round(endTime - startTime),
        provenance: {
          physical_capture_likelihood: result.physical_capture_likelihood,
          synthetic_generation_likelihood: result.synthetic_generation_likelihood,
          capture_chain_consistency: result.capture_chain_consistency,
          semantic_authenticity: result.semantic_authenticity
        },
        forensics: {
          explanation: result.explanation,
          signals: result.signals,
          metadata: {
            synthetic_probability: result.synthetic_generation_likelihood,
            impersonation_probability: result.classification === 'deepfake' ? result.confidence : 0,
            engine_source: 'Inference-Engine-Alpha',
            semantic_priors_detected: result.semantic_priors
          }
        },
        filePreview: parts[0]?.mimeType.startsWith('image/') ? `data:${parts[0].mimeType};base64,${parts[0].data}` : undefined
      };
    } catch (error) {
      console.error("Analysis Error:", error);
      throw new Error("The analysis could not be completed. This can happen if the media is too low-quality or contains ambiguous signals.");
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef } from 'react';
import { Upload, ShieldCheck, AlertCircle, Loader2, Play, Info, Eye, Layers, Activity, FileText, Cpu, UserCheck, Search, Database, Fingerprint, Link2Off, Sparkles, Scale, CheckCircle2 } from 'lucide-react';
import { MediaType, DetectionIncident, Severity, MediaPart, ClassificationType } from '../types';
import { geminiService } from '../services/geminiService';
import { MAX_FILE_SIZE_MB, VIDEO_FRAME_COUNT } from '../constants';

interface DetectionConsoleProps {
  onIncidentDetected: (incident: DetectionIncident) => void;
}

const DetectionConsole: React.FC<DetectionConsoleProps> = ({ onIncidentDetected }) => {
  const [file, setFile] = useState<File | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState<DetectionIncident | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      if (selectedFile.size > 200 * 1024 * 1024) {
        setError("File exceeds 200MB system limit.");
        setFile(null);
        return;
      }
      setFile(selectedFile);
      setResult(null);
      setError(null);
    }
  };

  const extractFrames = async (videoFile: File): Promise<MediaPart[]> => {
    return new Promise((resolve, reject) => {
      const video = document.createElement('video');
      video.preload = 'metadata';
      video.src = URL.createObjectURL(videoFile);
      video.muted = true;
      video.playsInline = true;

      video.onloadedmetadata = async () => {
        const duration = video.duration;
        const frames: MediaPart[] = [];
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');

        for (let i = 0; i < VIDEO_FRAME_COUNT; i++) {
          const time = (duration / VIDEO_FRAME_COUNT) * i;
          video.currentTime = time;
          await new Promise(r => video.onseeked = r);

          canvas.width = video.videoWidth > 1280 ? 1280 : video.videoWidth;
          canvas.height = (canvas.width / video.videoWidth) * video.videoHeight;

          if (ctx) {
            ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
            const base64 = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];
            frames.push({ data: base64, mimeType: 'image/jpeg' });
          }
        }
        URL.revokeObjectURL(video.src);
        resolve(frames);
      };
      video.onerror = () => reject("Failed to process media frames.");
    });
  };

  const runAnalysis = async () => {
    if (!file) return;
    setIsAnalyzing(true);
    setError(null);

    try {
      const isVideo = file.type.startsWith('video/');
      const mediaType = isVideo ? MediaType.VIDEO : file.type.startsWith('audio/') ? MediaType.AUDIO : MediaType.IMAGE;

      let parts: MediaPart[] = [];

      if (isVideo) {
        parts = await extractFrames(file);
      } else {
        if (file.size > MAX_FILE_SIZE_MB * 1024 * 1024) {
          throw new Error(`File size exceeds ${MAX_FILE_SIZE_MB}MB limit.`);
        }

        const reader = new FileReader();
        const base64Promise = new Promise<string>((resolve, reject) => {
          reader.onload = () => resolve((reader.result as string).split(',')[1]);
          reader.onerror = () => reject("Failed to read file.");
          reader.readAsDataURL(file);
        });
        const base64 = await base64Promise;
        parts = [{ data: base64, mimeType: file.type }];
      }

      const detection = await geminiService.analyzeMedia(file.name, mediaType, parts);

      setResult(detection);
      onIncidentDetected(detection);
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'The verification could not be completed at this time.');
    } finally {
      setIsAnalyzing(false);
    }
  };

  const getStatusColor = (classification: ClassificationType) => {
    if (classification === 'genuine') return 'emerald';
    if (classification === 'deepfake') return 'red';
    if (classification === 'hybrid') return 'purple';
    return 'blue'; 
  };

  const color = result ? getStatusColor(result.classification) : 'slate';

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in slide-in-from-bottom-4 duration-500">
      <div className="space-y-6">
        <div 
          onClick={() => !isAnalyzing && fileInputRef.current?.click()}
          className={`group relative border-2 border-dashed rounded-3xl p-12 text-center transition-all cursor-pointer overflow-hidden ${
            isAnalyzing ? 'opacity-50 cursor-not-allowed' : ''
          } ${
            file ? 'border-blue-500 bg-blue-500/5' : 'border-slate-800 hover:border-slate-600 hover:bg-slate-900'
          }`}
        >
          <input type="file" ref={fileInputRef} className="hidden" onChange={handleFileChange} accept="image/*,video/*,audio/*" disabled={isAnalyzing} />
          <div className="relative z-10 flex flex-col items-center">
            <div className={`w-16 h-16 bg-slate-800 rounded-2xl flex items-center justify-center mb-4 transition-transform group-hover:scale-110 duration-300 ${file ? 'bg-blue-600/20 text-blue-400' : 'text-slate-500'}`}>
              <Upload className="w-8 h-8" />
            </div>
            {file ? (
              <div className="space-y-1">
                <p className="font-bold text-white text-lg">{file.name}</p>
                <p className="text-[10px] text-blue-500 font-black uppercase tracking-widest">Media Loaded</p>
              </div>
            ) : (
              <div>
                <p className="font-bold text-white text-lg uppercase tracking-tight italic">Select Media for Analysis</p>
                <p className="text-[10px] text-slate-500 mt-2 font-black uppercase tracking-widest">Upload a file to check for manipulation</p>
              </div>
            )}
          </div>
        </div>

        {file && !isAnalyzing && !result && (
          <button 
            onClick={runAnalysis}
            className="w-full bg-blue-600 hover:bg-blue-500 text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-900/30 transition-all flex items-center justify-center gap-3 uppercase tracking-widest italic"
          >
            <ShieldCheck className="w-6 h-6" />
            Analyze Authenticity
          </button>
        )}

        {isAnalyzing && (
          <div className="w-full bg-slate-900 border border-slate-800 p-10 rounded-3xl text-center space-y-6 shadow-2xl">
            <Loader2 className="w-12 h-12 text-blue-500 animate-spin mx-auto" />
            <div className="space-y-2">
              <p className="text-xl font-black text-white uppercase italic tracking-tighter">Scanning Media Channels</p>
              <p className="text-[10px] text-blue-400 font-mono animate-pulse uppercase tracking-widest font-bold">DETECTING_DIGITAL_SIGNS</p>
            </div>
            <div className="w-full bg-slate-800 h-1 rounded-full overflow-hidden">
              <div className="h-full bg-blue-500 animate-[loading_2s_ease-in-out_infinite] w-1/3"></div>
            </div>
          </div>
        )}

        {error && (
          <div className="bg-red-500/10 border border-red-500/50 p-4 rounded-xl flex gap-3 text-red-400 animate-in fade-in zoom-in">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p className="text-sm font-medium">{error}</p>
          </div>
        )}

        {result && (
           <div className="space-y-4 animate-in slide-in-from-left-4">
              <div className="grid grid-cols-2 gap-4">
                 <div className="p-4 bg-slate-900 border border-slate-800 rounded-2xl text-center">
                    <p className="text-[8px] text-slate-500 font-black uppercase tracking-widest mb-1">Physical Signal Match</p>
                    <p className="text-sm font-mono font-bold text-emerald-400">{Math.round(result.provenance.physical_capture_likelihood * 100)}%</p>
                 </div>
                 <div className="p-4 bg-slate-900 border border-slate-800 rounded-2xl text-center">
                    <p className="text-[8px] text-slate-500 font-black uppercase tracking-widest mb-1">Authenticity Score</p>
                    <p className={`text-sm font-mono font-bold ${result.provenance.semantic_authenticity > 0.8 ? 'text-emerald-400' : 'text-purple-400'}`}>
                      {result.provenance.semantic_authenticity > 0.8 ? 'Natural' : 'Patterned'}
                    </p>
                 </div>
              </div>
              <div className={`p-5 bg-slate-900 border border-slate-800 rounded-2xl flex justify-between items-center ${result.classification === 'genuine' ? 'border-emerald-500/30 bg-emerald-500/5 shadow-[0_0_15px_rgba(16,185,129,0.1)]' : result.classification === 'hybrid' ? 'border-purple-500/30 bg-purple-500/5' : ''}`}>
                 <div>
                   <p className="text-[9px] text-slate-500 font-black uppercase tracking-widest mb-1">Final Classification</p>
                   <p className={`text-sm font-black uppercase italic ${result.classification === 'genuine' ? 'text-emerald-400 underline decoration-2 underline-offset-4' : result.classification === 'hybrid' ? 'text-purple-400' : 'text-red-400'}`}>
                      {result.classification === 'hybrid' ? 'AI-ASSISTED CONTENT' : result.classification.replace('_', ' ')}
                   </p>
                 </div>
                 <div className={`p-3 rounded-xl ${result.classification === 'genuine' ? 'bg-emerald-500 text-white shadow-lg' : result.classification === 'hybrid' ? 'bg-purple-500/10 text-purple-500' : 'bg-red-500/10 text-red-500'}`}>
                    {result.classification === 'genuine' ? <CheckCircle2 className="w-6 h-6" /> : result.classification === 'hybrid' ? <Sparkles className="w-6 h-6" /> : <ShieldCheck className="w-6 h-6" />}
                 </div>
              </div>
           </div>
        )}
      </div>

      <div className={`bg-slate-900 border border-slate-800 rounded-3xl overflow-hidden flex flex-col min-h-[600px] shadow-2xl relative`}>
        {result ? (
          <div className="flex-1 flex flex-col animate-in fade-in zoom-in-95 duration-500">
            <div className={`p-8 border-b border-slate-800 ${color === 'emerald' ? 'bg-emerald-500/5' : color === 'purple' ? 'bg-purple-500/5' : 'bg-red-500/5'}`}>
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-5">
                  <div className={`p-4 rounded-2xl shadow-xl ${color === 'emerald' ? 'bg-emerald-500' : color === 'purple' ? 'bg-purple-500' : 'bg-red-500'}`}>
                    {result.classification === 'hybrid' ? <Sparkles className="w-7 h-7 text-white" /> : 
                     result.classification === 'ai_generated' ? <Cpu className="w-7 h-7 text-white" /> : 
                     <UserCheck className="w-7 h-7 text-white" />}
                  </div>
                  <div>
                    <h3 className="font-black text-2xl uppercase tracking-tighter italic text-white">
                      {result.classification === 'genuine' ? 'Authentic Media' : 
                       result.classification === 'hybrid' ? 'AI-Modified Media' : 
                       'Synthetic Content'}
                    </h3>
                    <p className="text-[10px] font-mono text-slate-500 font-bold uppercase tracking-[0.2em]">ANALYSIS_CONFIDENCE: {result.confidenceScore}%</p>
                  </div>
                </div>
              </div>
            </div>

            <div className="p-10 space-y-10 flex-1 overflow-y-auto custom-scrollbar">
              <div className="relative rounded-2xl overflow-hidden aspect-video bg-black border border-slate-800 shadow-inner group">
                {result.filePreview && <img src={result.filePreview} className="w-full h-full object-contain" alt="Preview" />}
                <div className="absolute inset-0 bg-blue-500/10 pointer-events-none animate-scan-line"></div>
                <div className="absolute bottom-4 left-4 p-2 bg-slate-950/80 backdrop-blur rounded border border-slate-800 text-[10px] font-mono text-blue-400 font-bold tracking-widest uppercase">
                  NODE_LOG: {result.id}
                </div>
              </div>

              <div className="space-y-8">
                <div>
                  <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-3">Verification Findings</h4>
                  <p className={`text-base leading-relaxed font-medium ${result.classification === 'hybrid' ? 'text-purple-300' : 'text-slate-300'}`}>
